import Link from 'next/link';
import { CalendarDays, Goal, Shield, Trophy, Users } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { sampleMatches, sampleScorers, sampleStandings } from '../lib/sample-data';
import type { MatchRow, Scorer, TeamStanding } from '../lib/types';
async function getData() {
  if (!supabase) {
    return { standings: sampleStandings, scorers: sampleScorers, matches: sampleMatches };
  }

  const [standingsRes, scorersRes, matchesRes] = await Promise.all([
    supabase.from('standings_view').select('*').order('pts', { ascending: false }).order('dg', { ascending: false }),
    supabase.from('scorers_view').select('*').limit(10),
    supabase.from('matches_public_view').select('*').limit(10),
  ]);

  return {
    standings: (standingsRes.data as TeamStanding[]) || sampleStandings,
    scorers: (scorersRes.data as Scorer[]) || sampleScorers,
    matches: (matchesRes.data as MatchRow[]) || sampleMatches,
  };
}

function StatCard({ icon: Icon, label, value }: { icon: any; label: string; value: string | number }) {
  return (
    <div className="rounded-2xl border border-slate-100 bg-white p-5 shadow-sm">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm text-slate-500">{label}</p>
          <p className="mt-1 text-2xl font-black text-slate-900">{value}</p>
        </div>
        <div className="rounded-2xl bg-emerald-100 p-3 text-emerald-700">
          <Icon size={24} />
        </div>
      </div>
    </div>
  );
}

export default async function HomePage() {
  const { standings, scorers, matches } = await getData();
  const goals = standings.reduce((total, team) => total + Number(team.gf || 0), 0);

  return (
    <main className="min-h-screen bg-slate-50 text-slate-900">
      <header className="bg-slate-950 text-white">
        <div className="mx-auto flex max-w-7xl items-center justify-between px-4 py-5">
          <div className="flex items-center gap-3">
            <div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-emerald-500 shadow-lg">
              <Trophy size={25} />
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tight">Torneos Malvagol</h1>
              <p className="text-sm text-slate-300">Sistema de estadísticas para fútbol 7</p>
            </div>
          </div>
          <Link href="/admin" className="rounded-xl bg-emerald-500 px-4 py-2 text-sm font-bold text-white hover:bg-emerald-600">
            Panel admin
          </Link>
        </div>
      </header>

      <section className="mx-auto max-w-7xl px-4 py-7">
        <div className="mb-7 rounded-3xl bg-gradient-to-br from-emerald-600 to-slate-900 p-6 text-white shadow-sm md:p-8">
          <p className="mb-2 font-semibold text-emerald-100">Liga activa</p>
          <h2 className="text-3xl font-black leading-tight md:text-5xl">Torneo Apertura Malvagol</h2>
          <p className="mt-3 max-w-xl text-emerald-50">Consulta posiciones, resultados, próximos partidos, goleadores y estadísticas actualizadas del torneo.</p>
        </div>

        <div className="mb-7 grid gap-4 md:grid-cols-4">
          <StatCard icon={Users} label="Equipos registrados" value={standings.length} />
          <StatCard icon={Goal} label="Goles anotados" value={goals} />
          <StatCard icon={CalendarDays} label="Partidos" value={matches.length} />
          <StatCard icon={Shield} label="Categoría" value="Fútbol 7" />
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          <section className="rounded-3xl border border-slate-100 bg-white p-5 shadow-sm lg:col-span-2">
            <h3 className="text-xl font-black">Tabla general</h3>
            <p className="mb-4 text-sm text-slate-500">Ordenada por puntos, diferencia de goles y goles a favor.</p>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b text-left text-slate-500">
                    <th className="py-3">#</th><th>Equipo</th><th>PJ</th><th>PG</th><th>PE</th><th>PP</th><th>GF</th><th>GC</th><th>DG</th><th>PTS</th>
                  </tr>
                </thead>
                <tbody>
                  {standings.map((team, index) => (
                    <tr key={team.id} className="border-b last:border-0 hover:bg-slate-50">
                      <td className="py-3 font-bold">{index + 1}</td>
                      <td className="font-semibold">{team.name}</td>
                      <td>{team.pj}</td><td>{team.pg}</td><td>{team.pe}</td><td>{team.pp}</td><td>{team.gf}</td><td>{team.gc}</td><td>{team.dg}</td>
                      <td className="font-black text-emerald-700">{team.pts}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          <aside className="rounded-3xl border border-slate-100 bg-white p-5 shadow-sm">
            <h3 className="mb-4 text-xl font-black">Goleadores</h3>
            <div className="space-y-3">
              {scorers.map((item, index) => (
                <div key={`${item.player}-${item.team}`} className="flex items-center justify-between rounded-2xl border border-slate-100 p-4">
                  <div>
                    <p className="font-bold">{index + 1}. {item.player}</p>
                    <p className="text-sm text-slate-500">{item.team}</p>
                  </div>
                  <p className="text-2xl font-black text-emerald-700">{item.goals}</p>
                </div>
              ))}
            </div>
          </aside>
        </div>

        <section className="mt-6 rounded-3xl border border-slate-100 bg-white p-5 shadow-sm">
          <h3 className="mb-4 text-xl font-black">Partidos</h3>
          <div className="grid gap-4 md:grid-cols-3">
            {matches.map((match) => (
              <div key={match.id} className="rounded-2xl border border-slate-100 bg-slate-50 p-4">
                <p className="text-sm text-slate-500">{new Date(match.match_date).toLocaleString('es-MX')} · {match.field}</p>
                <p className="mt-2 text-lg font-black">{match.home_team}</p>
                <p className="text-sm font-semibold text-slate-400">vs</p>
                <p className="text-lg font-black">{match.away_team}</p>
                {match.home_goals !== null && match.away_goals !== null && (
                  <p className="mt-3 text-2xl font-black text-emerald-700">{match.home_goals} - {match.away_goals}</p>
                )}
              </div>
            ))}
          </div>
        </section>
      </section>
    </main>
  );
}
